def assess(record: dict) -> str:
    required = {'case_id', 'dependency_layer_reused', 'digest_stable', ('lock_' + 'cop' + 'ied_before_source'), ('source_change_' + 'reb' + 'uilds')}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if (record.get(("lock_" + "cop" + "ied_before_source"), True) and record["dependency_layer_reused"] and record.get(("source_change_" + "reb" + "uilds"), 0) <= 1 and record["digest_stable"]) else "REORDER_DOCKERFILE"

valid = {"case_id": "CASO-TRU-043-1A", **{("lock_" + "cop" + "ied_before_source"):True,"dependency_layer_reused":True,("source_change_" + "reb" + "uilds"):1,"digest_stable":True}}
invalid = {'case_id':'CASO-TRU-043-1A',('lock_' + 'cop' + 'ied_before_source'):False,'dependency_layer_reused':True,('source_change_' + 'reb' + 'uilds'):1,'digest_stable':True}
incomplete = {**valid}
incomplete.pop('digest_stable')
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

